def _entropy(prob: float) -> float:
    """二值熵 H(p) = -p*log2(p) - (1-p)*log2(1-p)。"""
    if prob <= 0.0 or prob >= 1.0:
        return 0.0
    return -prob * math.log2(prob) - (1 - prob) * math.log2(1 - prob)


class FlowOptimizer:
    """心流优化器：互信息 + BKT + 难度调节。

    compute_flow(skill_probs, task_difficulty) → dict
    """

    def __init__(self, bkt_params: dict | None = None, config: dict | None = None):
        self._bkt_params = bkt_params or {}
        self._config = config or {}
        self._bkt = BKTEngine(
            prior=bkt_params.get("prior", 0.3) if bkt_params else 0.3,
            guess=bkt_params.get("guess", 0.1) if bkt_params else 0.1,
            slip=bkt_params.get("slip", 0.1) if bkt_params else 0.1,
            learn=bkt_params.get("learn", 0.2) if bkt_params else 0.2,
        )
